const sendContactEmail = async (data) => {
  return await fetch('https://api.brevo.com/v3/smtp/email', {
    method: 'POST',
    headers: { 'api-key': 'YOUR_API_KEY' },
    body: JSON.stringify({ ...data })
  });
};

